// Helper function to get all station slugs
export const getAllStationSlugs = () => Object.keys(railwayStations);

// Helper function to get station data by slug
export const getStationBySlug = (slug) => railwayStations[slug] || null;

// Helper function to get nearby stations for cross-linking
export const getNearbyStations = (currentSlug) => {
  const regionMap = {
    "agra-cantt": ["agra-fort", "mathura", "gwalior", "new-delhi"],
    "agra-fort": ["agra-cantt", "mathura", "gwalior", "new-delhi"],
    "new-delhi": ["old-delhi", "nizamuddin", "anand-vihar", "agra-cantt"],
    "old-delhi": ["new-delhi", "nizamuddin", "anand-vihar", "ambala"],
    "nizamuddin": ["new-delhi", "old-delhi", "anand-vihar", "agra-cantt"],
    "anand-vihar": ["new-delhi", "old-delhi", "nizamuddin", "lucknow"],
    "jaipur": ["ajmer", "jodhpur", "udaipur", "agra-cantt"],
    "chandigarh": ["ambala", "kalka", "pathankot", "new-delhi"],
    "varanasi": ["prayagraj", "ayodhya", "lucknow", "gwalior"],
    "lucknow": ["kanpur", "ayodhya", "varanasi", "prayagraj"],
    "haridwar": ["rishikesh", "dehradun", "ambala", "new-delhi"],
    "dehradun": ["haridwar", "rishikesh", "ambala", "kathgodam"],
    "amritsar": ["pathankot", "jammu", "chandigarh", "ambala"],
    "jodhpur": ["jaipur", "udaipur", "ajmer", "agra-cantt"],
    "udaipur": ["jodhpur", "ajmer", "jaipur", "agra-cantt"],
    "ayodhya": ["lucknow", "varanasi", "prayagraj", "kanpur"],
    "mathura": ["agra-cantt", "agra-fort", "new-delhi", "jaipur"],
    "rishikesh": ["haridwar", "dehradun", "kathgodam", "new-delhi"],
    "kathgodam": ["dehradun", "rishikesh", "haridwar", "new-delhi"],
    "kalka": ["chandigarh", "ambala", "pathankot", "new-delhi"],
    "prayagraj": ["varanasi", "lucknow", "ayodhya", "kanpur"],
    "ajmer": ["jaipur", "jodhpur", "udaipur", "new-delhi"],
    "jammu": ["pathankot", "amritsar", "chandigarh", "new-delhi"],
    "pathankot": ["amritsar", "jammu", "chandigarh", "kalka"],
    "gwalior": ["agra-cantt", "jaipur", "new-delhi", "kanpur"],
    "ambala": ["chandigarh", "kalka", "new-delhi", "amritsar"],
    "kanpur": ["lucknow", "prayagraj", "agra-cantt", "varanasi"]
  };

  return (regionMap[currentSlug] || [])
    .filter(slug => railwayStations[slug])
    .map(slug => ({
      slug,
      name: railwayStations[slug].name,
      city: railwayStations[slug].city,
      stationCode: railwayStations[slug].stationCode
    }));
};
